#include <stdio.h>

int main(int argc, char* argv[])
{
	int numberOfDancers, whiteSuitCost, blackSuitCost;
	scanf("%d %d %d", &numberOfDancers, &whiteSuitCost, &blackSuitCost);

	//Getting the cheapest suit.
	int cheapSuitCost, cheapSuitFlag;
	if(whiteSuitCost < blackSuitCost)
		cheapSuitCost = whiteSuitCost;
	else
		cheapSuitCost = blackSuitCost;

	int dancers[numberOfDancers];

	//Getting dancers arrangment.
	int i;
	for(i = 0;i < numberOfDancers;i++)
		scanf("%d", &dancers[i]);

	//Buy the cheapest suit for the center dancer.
	int cost = 0;
	if(numberOfDancers % 2 != 0)
	{
		if(dancers[numberOfDancers/2] == 2)
			cost += cheapSuitCost;
	}


	int j;
	if(numberOfDancers % 2 == 0)
		j = numberOfDancers / 2;
	else
		j = (numberOfDancers/2) + 1;

	for(i = (numberOfDancers/2) - 1;i >= 0;i--)
	{	

		if(dancers[i] + dancers[j] == 1)
		{
			printf("-1");
			return 0;
		}
		else if(dancers[i] == 2 && dancers[j] == 2)
			cost += (cheapSuitCost * 2);
		else if(dancers[i] == 1 && dancers[j] == 2)
			cost += blackSuitCost;
		else if	(dancers[i] == 2 && dancers[j] == 1)
			cost += blackSuitCost;
		else if(dancers[i] == 0 && dancers[j] == 2)
			cost += whiteSuitCost;
		else if(dancers[i] == 2 && dancers[j] == 0)
			cost += whiteSuitCost;

		j++;
	}

	printf("%d", cost);

	return 0;
}

