use std::io::{self, Read};

fn main() -> () {

    let mut buffer = String::new();
    let stdin = io::stdin();
    let mut handle = stdin.lock();

    handle.read_to_string(&mut buffer).expect("stdin");

    let mut arr : Vec<_> = buffer.split_whitespace().map(|x| x.parse::<i64>().unwrap() ).collect();

    let n = arr[0] as usize;
    let a = arr[1] as usize;
    let b = arr[2] as usize;

    let v = arr.drain(3..).collect::<Vec<i64>>();

    let mut cost = 0usize;

    for i in 0..n / 2 + n % 2 {
        if v[i] != 2 && v[n-1-i] != 2 {
            if v[i] != v[n-1-i] {
                println!("-1");
                return
            }
        } else if v[i] == 2 && v[n-1-i] == 2 {
            use std::cmp;
            cost += cmp::min( a, b ) * if i != n-1-i { 2 } else { 1 };
        } else if v[i] != 2 && i != n-1-i {
            cost += if v[i] == 0 { a } else { b };
        } else if v[n-1-i] != 2 && i != n-1-i {
            cost += if v[n-1-i] == 0 { a } else { b };
        } else {
            panic!();
        }
    }

    println!("{:?}",cost);
}
